#!/usr/bin/env bash
# fa-deprocess-fa.sh — 失效分析 FA / 缺陷根因闭环（电性定位→物理 deprocess→FA→反馈改工艺） SOP walkthrough for 半导体芯片制造工艺.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="半导体芯片制造工艺"
WORKFLOW="失效分析 FA / 缺陷根因闭环（电性定位→物理 deprocess→FA→反馈改工艺）"

usage() {
  cat <<EOF
fa-deprocess-fa.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./fa-deprocess-fa.sh             # interactive
  ./fa-deprocess-fa.sh --dry-run
  ./fa-deprocess-fa.sh --json
  ./fa-deprocess-fa.sh --explain
  ./fa-deprocess-fa.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "失效分析 FA / 缺陷根因闭环（电性定位→物理 deprocess→FA→反馈改工艺）" 工作流。

一句话: 从「一个 die fail（yield bin / 客户退货 / 可靠性 fail）」到「找到物理根因并反馈改工艺/设计的 corrective action」。FA 不修单片，而是逆向找根因闭环改善。 (evidence: [T06-glossary FA, T03-S002])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 物理硬约束 ⇄ 良率/成本经济约束（第一性双重张力）: 半导体工艺的每个决策都同时受两类硬约束——物理/化学/材料（量子隧穿、短沟道效应、RC 延迟、热预算、缺陷物理）与良率/成本经济（D0 缺陷密度、每片晶圆成本、wph、折旧）；摩尔定律首先是**经济命
  • 设备/工艺是必要非充分，良率 know-how 才是真壁垒: 能不能做先进制程，从来不是「有没有 EUV/光刻机」单一决定的——设备 + 材料 + 刻蚀/沉积 + 工艺整合 + 良率爬坡**五要素缺一不可**，而良率 ramp 的 know-how 是 silo

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**失效复现与电性定位**：先用电性测试（ATE/参数测试）确认 fail 模式，用 fault isolation（scan diagnosis / 光发射 EMMI / OBIRCH 热点）把 fail 缩到具体 net/区域。 (evidence: [T03-S002])"
  "**非破坏分析先行**：X-ray / 声学扫描 SAM / 红外，避免一上来就破坏样品丢信息。"
  "**物理 deprocess + FA**：逐层去层（deprocess）后用 SEM/TEM/FIB 看缺陷物理形貌，做材料分析（EDX/SIMS）。"
  "**根因判定**：判定是工艺缺陷（particle/桥接/空洞）、设计弱点（marginal layout）还是材料/可靠性问题。"
  "**反馈 corrective action + 验证**：把根因反馈到对应工艺步骤/设计规则/设备，split 验证后关闭。 (evidence: [T03-S007])"
)
declare -a FAILURE_MODES=(
  "**不先电性定位就盲 FIB**：在 mm² 级 die 上找 nm 级缺陷如大海捞针，烧掉样品和数周 —— 先 scan diagnosis/EMMI/OBIRCH 缩到 net 级再切。"
  "**一上来破坏 deprocess**：丢失原始失效证据（充填物/可移动离子/电荷） —— 非破坏（X-ray/SAM/红外）先行。"
  "**把表象当根因**：看到 particle 就归因 particle，没追到 particle 从哪来，改了照样复发 —— 追到 particle 源工艺步骤/设备再 corrective。"
  "**FA 不闭环到工艺**：报告归档但工艺没改，同失效再现 —— 强制每个 FA 出 corrective action + split 验证关闭。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "fa-deprocess-fa-walkthrough"
fi
